var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐엑- 헥-","JPN":"はあ……ふえっ……","ENG":"*Huff...* *Huff...*","TWN":"呼，呼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"후아… 이 정도면 따돌린 것 같은데요?","JPN":"ふう……これくらいなら引き離せましたよね？","ENG":"Whew... I think we lost them.","TWN":"呼…應該安全了吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"큭, 분하다. 눈앞에 보물을 잔뜩 두고 도망치는 신세라니.","JPN":"くっ、悔しい。宝を目の前にして逃げるなんて。","ENG":"Kgh, I can't believe this. I have to run away from all that treasure right in front of my eyes.","TWN":"真是生氣，寶藏就近在眼前，我們卻只能逃。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아까 전엔 보물에 하나도 관심 없다며?","JPN":"さっきは宝に興味はないと言ってなかったか？","ENG":"Didn't you say you weren't interested in the treasure?","TWN":"你之前還說對寶藏不感興趣？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"관심 없을 리 있겠냐? 이래봬도 난 해적이라고.","JPN":"そんなわけないだろう？　こう見えても、俺は海賊なんだよ。","ENG":"You believed that? I'm still a pirate, you know.","TWN":"怎麼可能不感興趣？畢竟我是個海盜。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"저기… 저희는 이제 어쩌면 좋죠?","JPN":"あの……俺たちはこれからどうしたらいいですか？","ENG":"Err... What do we do now?","TWN":"那個…我們現在怎麼辦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐야? 넌 또 왜 따라왔어? 애초에 우리랑 같은 해적도 아니잖아?","JPN":"何だ？　お前、なんでまたついて来たんだよ。だいたい、俺たちと同じ海賊でもないだろう？","ENG":"Huh? Why are you following us? You're not even a pirate like the rest of us.","TWN":"搞什麼？你怎麼又跟上來啦？你又不是海盜！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"그, 그럴 수가…","JPN":"そ、そんな……","ENG":"B-but...","TWN":"怎…怎麼會…"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어쩜! 생각이 짧네요, 터커 씨!","JPN":"もう！　浅はかですね、ターカーさん！","ENG":"Oh, Tucker! How can you be so shortsighted?","TWN":"嘖嘖，你的眼光太短淺啦，塔克！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"헌터들과 마주쳤을 때 협상카드로 쓸 인질이 하나쯤은 있어야죠!","JPN":"ハンターと出くわした時に交渉で使える人質が一人くらいはいないと！","ENG":"We need a hostage to use as a bargaining chip if we run into more hunters!","TWN":"我們要抓一個來當之後遇到獵人時的談判籌碼吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"예전에 샌님처럼 생겼다고 놀린 건 사과할게, 탈리. 네가 우리 중에 제일 해적답다 야.","JPN":"前に頭でっかちってからかったの、謝っておくよ、タリー。お前が俺たちの中で一番海賊っぽいな。","ENG":"I'm sorry for teasing you about being a dweeb before, Tallie. You're the most pirate-like out of all of us.","TWN":"塔莉，我為之前取笑你像傻子而道歉，你是我們當中最像海盜的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"앗?","JPN":"あっ？","ENG":"Oh?","TWN":"蛤？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저기 좀 보세요! 숲 속에 커다란 건물이 있어요!","JPN":"あそこを見てください！　森の中に大きな建物がありますわ！","ENG":"Look over there! There's a huge building within the forest!","TWN":"看，樹林裡有間大房子！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저건… 해적 요새네.","JPN":"あれは……海賊の要塞だな。","ENG":"That's... a pirate fortress.","TWN":"那是…海盜堡壘。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"사람은 살지 않는 것 같네요.","JPN":"人は住んでないみたいですね。","ENG":"It doesn't look like anyone's still living there.","TWN":"這裡似乎沒有人居住。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"오랫동안 버려졌구만. 사람 흔적은 없고 거의 터만 남았어.","JPN":"長い間打ち捨てられてたんだ。人の形跡はないし、ほとんど基礎だけ残ってる。","ENG":"It's been abandoned for a long time. There are no signs of life.","TWN":"看來這裡已經廢棄許久，沒有任何生活的跡象，只有一片廢墟。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐음- 해골 같은 건 하나도 안 보여요. 사고가 있었던 건 아닌가봐요.","JPN":"ふーむ、骸骨とかは一つも見当たりません。事故があったわけではなさそうです。","ENG":"Hmm... I don't see any skeletons. I guess there wasn't an accident over here.","TWN":"嗯，我沒看到任何骷髏頭或其他東西，是不是發生過什麼意外？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯…？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"이것 좀 보세요. 여기에도 금화가 떨어져 있네요.","JPN":"これを見てください。ここにも金貨が落ちてますね。","ENG":"Check this out. There's gold over here too.","TWN":"看看這個，這裡也有一枚金幣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"쳇, 아쉬운 대로 그거라도 일단 챙기자고.","JPN":"ちっ、残念だけどそれだけでも拾っておこう。","ENG":"Tch. Let's at least take this.","TWN":"嘖，有一點算一點。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이 금화는… 소금기가 묻어 있어.","JPN":"この金貨……塩気がある。","ENG":"The gold coin... It's still got some salt on it.","TWN":"這枚金幣…沾了鹽。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐 어때서 그래? 씻어내면 다 똑같은 금화잖아.","JPN":"それがどうかしたのか？　洗ったら全部同じ金貨じゃないか。","ENG":"So what? Wash it off and you got yourself a perfectly good gold coin.","TWN":"有什麼關係？洗一洗，還不是一樣的金幣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"우리가 봤던 금화들은 바닷가에 쌓여 있었지. 해류에 떠밀려온 물건이란 뜻이야.","JPN":"あたしたちが見た金貨は、海辺に積みあがっていた。海流に流されて来たものってことだ。","ENG":"All the gold we found was piled up by the beach. This means that the current carried it all the way here.","TWN":"我們看到的金幣都堆在沙灘上。這說明它們是被水流沖上來的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런 물건이 이런 섬 한가운데 고지에도 있다고. 이상하지 않아?","JPN":"それが、こんな島の真ん中の高台にもある。おかしくないか？","ENG":"But seeing this at a high point on the island? Doesn't that sound off?","TWN":"在這樣一個小島中央的高處竟然也有這樣的東西。這不是很奇怪嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"…뭐가 문젠지 전혀 모르겠는데?","JPN":"……何がおかしいのかさっぱりわかんないな。","ENG":"...I don't see what the big deal is.","TWN":"…這有什麼問題嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아무려면 어때요! 바닷가가 아니라 여기서도 숨겨진 보물을 찾을 수 있다는 뜻이잖아요?!","JPN":"いいじゃないですか！　海辺じゃなくて、ここでも隠れた宝を探せるって意味でしょう！？","ENG":"Who cares? It just means we can find hidden treasure here too!","TWN":"不管怎樣！這不就表示在這裡也能找到隱藏的寶藏！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"섬에서 보물찾기는 바다 모험 중에서도 궁극의 낭만이라고요!","JPN":"島での宝探しは、海の冒険の中でも究極のロマンです！","ENG":"Finding treasure on an island is the ultimate dream of sea-adventuring!","TWN":"在島上尋寶是海上探險的終極浪漫！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"낭만…","JPN":"ロマン……","ENG":"Dream...","TWN":"浪漫…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그러고 보니 잭은 낭만을 찾으라고 했었지.","JPN":"そういえば、ジャックはロマンを探せって言ってたな。","ENG":"Come to think of it, Jack told us to find the dream too.","TWN":"仔細想想，傑克叫我去尋找浪漫。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 낭만이라는 건… 이 섬에 있는 보물들을 말한 건가?","JPN":"そのロマンてのは……この島にある宝のことだったのか？","ENG":"When he said \\"dream...\\" Did he mean the treasure on this island?","TWN":"他說的浪漫…是指島上的寶藏嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇겠지. 보물이 아니었으면 위험까지 무릅쓰며 심해역에 올 이유가 없잖아?","JPN":"そうだろうな。宝じゃなかったら、危険だってわかってるのに深海域まで来る理由なんてないよ。","ENG":"I guess so. Why would anyone risk coming to the deep sea area if there isn't any treasure to be found?","TWN":"應該是吧，如果不是為了寶藏，誰會冒險來深水域？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"하지만 아직 이해가 안 되는 부분이 있어요.","JPN":"でも、まだ理解できないことがあるんです。","ENG":"But there's still one thing I can't wrap my head around.","TWN":"但我還是有些不明白。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"그 보물사냥꾼이란 사람은 어째서 미끼를 자처한 거죠? 그럼 정작 자신은 아무 이득도 못 볼 텐데요.","JPN":"あのトレジャーハンターって人は、どうしてオトリに名乗り出たんですか？　それじゃあ、結局自分は何の得もしないのに。","ENG":"Why did that treasure hunter volunteer to become bait? Doesn't that mean he won't get anything for himself?","TWN":"那個寶藏獵人為什麼說自己是誘餌呢？這對他有什麼好處。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"글쎄? 나중에 찾아와서 자기 몫을 떼어달라고 하려던 거 아냐?","JPN":"さあ？　後で自分の分をもらいに来ようとしたんじゃないか？","ENG":"Who knows? Maybe he'll come around and demand that we give up his share.","TWN":"這個嘛？他會不會之後來找我們討屬於自己那份寶藏？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"자신이 크라켄을 따돌리고 살아남을 거라 확신한다고요? 대체 어떤 사람이 선뜻 그런 희생을 감수합니까?","JPN":"クラーケンから生き残れると確信したってことですか？　誰がそんな犠牲を覚悟するんですか？","ENG":"So he was sure he'd survive Kraken? What kind of person would make such a sacrifice?","TWN":"他肯定自己能逃過克拉肯的攻擊活下來？什麼樣的人會做出這樣的犧牲？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"아주 값진 희생이지. 그러니 우리가 그 사람 몫만큼 보물을 더 챙기면 되는 거야.","JPN":"高尚な犠牲だよ。だから俺たちがあの人の分まで宝を手に入れておけばいいのさ。","ENG":"It was a noble sacrifice. That's why we need to take more treasure to include his share.","TWN":"這是一個巨大的犧牲，所以我們必須確保他能得到他那份寶藏。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"서둘러. 보물 경쟁에서 밀린 놈들이 여기로 몰려오기 전에 우리가 다 쓸어 담자고.","JPN":"急げよ。お宝競争で負けたやつらがここに押し寄せてくる前に、俺たちが全部かき集めておこう。","ENG":"Hurry. We gotta sweep this place clean before the losers from the beach start swarming over to this side.","TWN":"快點行動吧，在被捲入寶藏鬥爭之前，我們把東西都帶出去。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어라…?","JPN":"あれ……？","ENG":"Huh...?","TWN":"嗯…？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"갑자기 보물지도가 반응하고 있네요.","JPN":"急に宝の地図が反応していますね。","ENG":"The treasure map is suddenly reacting to something.","TWN":"藏寶圖突然有了反應。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"보물지도라고? 그건 그냥 데이터패드잖아?","JPN":"宝の地図？　それはただのデータパッドだろう？","ENG":"Treasure map? Wasn't that thing just a data pad?","TWN":"藏寶圖？不就是個資料板嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"에이버리가 물건을 숨긴 장소를 표시해 놓은 거야.","JPN":"エイバリーがブツを隠した場所を記しておいたものだ。","ENG":"It marks the spot where Avery hid his stuff.","TWN":"艾維利在他藏東西的地方做了標記。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"풍랑 속에서도 멀쩡히 작동하는 걸 보면 아주 튼튼한 데이터패드네.","JPN":"この風浪の中でもちゃんと作動しているとは、かなり丈夫なデータパッドだな。","ENG":"Seems like a sturdy data pad, seeing how it still works after all that stormy weather.","TWN":"從它在暴風雨中倖存下來的事實來看，這是一個相當堅固的資料板。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"대해적 에이버리의 소지품이 숨겨진 지도…?","JPN":"大海賊エイバリーの持ち物が隠された地図……？","ENG":"A map where the Great Pirate Avery hid his loot...?","TWN":"藏有大海盜艾維利遺物的地圖…？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼 보물인 게 당연하잖아! 에이버리는 모든 해적의 우상이라고!","JPN":"そりゃあ、当然宝だろう！　エイバリーはすべての海賊の偶像なんだぞ！","ENG":"It's got to be more treasure! Avery is the role model for us pirates, after all!","TWN":"這就是個寶藏啊！艾維利可是所有海盜的偶像！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그야 당연하죠!","JPN":"当然ですわ！","ENG":"That's right!","TWN":"那當然了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"표시가 멀지 않은 곳에 있어요. 한 번 가봐요!","JPN":"印はここから遠くないところにありますよ。行ってみましょう！","ENG":"It's not too far from here. Let's go check it out!","TWN":"標記就在不遠處，快去看看吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"헥 헥… 같이 좀 가. 나도…! 보물이 보고 싶다고!","JPN":"ヘッ、ヘッ……一緒に行こうよ。俺も……！　宝が見たい！","ENG":"*Huff...* Huff...* Wait... for me...! I wanna see the treasure too!","TWN":"呼呼…一起去吧。我也…想看看寶藏！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"후아- 무슨 보물을 이렇게 높은 곳에 숨겨둔 거죠?","JPN":"ふわあーなんて高いところに宝を隠しておいたんですか！","ENG":"Huah-! Why would anyone hide treasure in such a high place?","TWN":"呼，這麼高的地方會藏著什麼寶藏？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"여긴… 섬의 꼭대기 같네.","JPN":"ここは……島の頂のようだな。","ENG":"This is... the island's highest point.","TWN":"這裡…似乎是島的最高處。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"좋아요! 이제 저쪽을 파보자고요!","JPN":"よしっ！　それでは、あそこを掘ってみましょう！","ENG":"All right! Let's start digging over there!","TWN":"很好！我們就好好探索一下這裡吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"케케… 삽질은… 자신 있으니… 맡기라고…!","JPN":"ケケ……掘るのは……自信あるから……任せろって……！","ENG":"Keke... Leave it to me...! I'm a pro-shoveler!","TWN":"呼呼…我有…鏟子…交給我吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"금방이라도 지쳐 쓰러질 것 같은데, 괜찮은 거야?","JPN":"今にでも倒れそうだけど、大丈夫なのか？","ENG":"You look like you're gonna faint any second now. You good?","TWN":"你還好嗎，看起來快要暈過去了？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"……선장?","JPN":"……船長？","ENG":"...Captain?","TWN":"……船長？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L31_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"오? 너희도 왔냐?","JPN":"おお？　お前らも来たか？","ENG":"Oh? You're all here too?","TWN":"喔？你們也來啦？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님?!","JPN":"船長！？","ENG":"Captain?!","TWN":"船長？！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님이 왜 보물이 숨겨진 곳에 있는 거예요?","JPN":"どうして船長がここにいるのですか？","ENG":"Why are you standing exactly where the treasure is supposed to be, Captain?","TWN":"船長，你為什麼會在藏寶物的地方？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 드라코가 왜 진짜 보물 스팟에 있어?!","JPN":"な、なんだ？　本当になんでドラコが宝の在りかにいるんだよ！？","ENG":"W-what? Why is Dracasia at the treasure spot?!","TWN":"搞什麼？德拉克，你怎麼會在真正的藏寶點？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"설마 동료와의 우정이 제일 값진 보물이다… 라는 허무한 결말은 아니겠지?! 응?!","JPN":"まさか、仲間との友情がもっとも価値のある宝だ……って虚しい結末じゃないだろうな！？　な！？","ENG":"It can't be a... \\"the most valuable treasure is the friends you made along this journey\\" kinda ending, right?!","TWN":"與同伴之間的友誼就是最珍貴的寶藏…你不會要說這種屁話吧？！嗯？！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"보물이라니, 뭔 소릴 하는 거야?","JPN":"宝って、何言ってんだ？","ENG":"Treasure? What are you talking about?","TWN":"什麼寶藏，你們說什麼呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"난 그냥 인증샷 찍기 좋은 데를 찾아서 온 거뿐이라고.","JPN":"あたしはただ、写真映えしそうなところを探して来ただけなんだよ。","ENG":"I'm here because it looked like the perfect place to take a selfie.","TWN":"我只是在找一個自拍的好地方。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…그러고 보니, 여기 절벽에선 섬 전체가 내려다보이네.","JPN":"……そういえば、この崖から島全体を見渡せる。","ENG":"...Now that you mention it, you can see the entire island from this cliff.","TWN":"…這麼一說，這座懸崖可以俯瞰整個島嶼。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"저 밑에선 아직도 싸우고 있구만. 지독한 녀석들.","JPN":"あの下ではまーだ戦ってんのか。懲りないやつらだぜ。","ENG":"I see that they're still fighting down there. How spiteful.","TWN":"那些傢伙還在下面打架。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"오오, 까만 수평선과 포화처럼 새빨간 하늘의 극단적인 대비! 엄청 예쁘네요.","JPN":"おお、黒い水平線と砲火のように真っ赤な空のコントラスト！　とてもキレイですわ。","ENG":"Ooh! The black horizon with the stark contrast of the crimson sky! It's so pretty!","TWN":"喔喔，黑色的地平線與砲火般的火紅天空之間形成的強烈對比，真是太美了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"어때? 쩔지? 아무 데서나 보기 힘든 광경이거든.","JPN":"どうだ？　すごいだろ？　滅多に見れない風景なんだ。","ENG":"Whaddaya think? Incredible, right? You can't see this every day.","TWN":"怎麼樣？很美吧？這可是難得一見的風景。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"가만.","JPN":"ちょっと。","ENG":"Wait.","TWN":"等下。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"심해역 한복판의 섬이라면… 설마 여기가?","JPN":"深海域のど真ん中にある島って……まさか、ここが？","ENG":"An island in the middle of the deep sea area... Could this place be...?","TWN":"深海域中心的島嶼…該不會就是這裡？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"맞아.","JPN":"そう。","ENG":"Yup.","TWN":"沒錯。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"전설의 에이버리 해적단이 본거지로 쓰던, 대양 한복판에 숨겨진 섬.","JPN":"伝説のエイバリー海賊団が本拠地にしていた、大海のど真ん中にある隠された島。","ENG":"This is the hidden island that the Great Pirate Avery and his gang used as their base.","TWN":"這座隱藏在大海中央的小島，曾經是傳說中的艾維利海盜團的據點。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"여기가 그 마하 섬이야.","JPN":"ここがあのマッハ島なんだよ。","ENG":"This is the one and only Macha Island.","TWN":"這裡就是瑪查島。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};